/********************************************************************************
*  THE ROSETTA STONE - UNIVERSAL DIAGNOSTIC
*  Purpose:  Tries every possible path to find the links array. It WILL
*            find it and tell you where it was. This ends the guesswork.
********************************************************************************/

let rawLinks = [];
let foundPath = 'none';

try {
  // Hypothesis 1: The data is correct: { json: { links: [...] } }
  if ($json && Array.isArray($json.links)) {
    rawLinks = $json.links;
    foundPath = 'CORRECT: $json.links';
  }
  // Hypothesis 2: The data is malformed: { links: [...] }
  else if ($item && Array.isArray($item.links)) {
    rawLinks = $item.links;
    foundPath = 'MALFORMED: $item.links';
  }
  // Hypothesis 3: It's a stringified array somewhere
  else if ($json && typeof $json.links === 'string') {
    rawLinks = JSON.parse($json.links);
    foundPath = 'STRING: Parsed from $json.links';
  }
  // Add more hypotheses here if needed, but one of these should hit.

} catch (error) {
  // This catch block makes the node un-crashable.
  const errorOutput = {
    json: {
      CRASH_ERROR: `The code crashed with error: ${error.message}`,
      INCOMING_ITEM_THAT_CAUSED_CRASH: $item,
    }
  };
  return errorOutput;
}


// --- Your filtering logic ---
const junkPatterns = [
  /\.xml$/i, /wp-sitemap/, /^\/\?/, /\/author\//, /\/category\//,
  /thank-you/, /\/wp-json\//, /\/feed\//, /oceanwp_library/, /sitemap_index/,
  /faq-sitemap/, /location-sitemap/, /newsletter-sitemap/, /job-sitemap/,
  /our_team-sitemap/, /post-sitemap/, /ebook-sitemap/, /page-sitemap/,
  /\.pdf$/i
];
const demoSlugs = [
  'cras-metus-sed-aliquet-risus-a-tortor', 'quis-ligula-lacinia-aliquet-mauris',
  'nulla-metus-metus-ullamcorper', 'luctus-non-massa-fusce-ac-turpis',
  'pellentesque-nibh-aenean-quam', 'conubia-nostra-per-inceptos',
];
const CLEAN_LINKS = rawLinks
  .filter(link => typeof link === 'string' && link.trim() !== '')
  .filter(link => !junkPatterns.some(pattern => pattern.test(link)))
  .filter(link => !demoSlugs.some(slug => link.includes(slug)));
// --- End filtering logic ---


// --- Build the definitive diagnostic output ---
const diagnosticOutput = {
  json: {
    // This tells us EXACTLY what path worked.
    FOUND_PATH: foundPath,
    // How many links we started with.
    RAW_LINK_COUNT: rawLinks.length,
    // How many links we ended with.
    CLEAN_LINK_COUNT: CLEAN_LINKS.length,
    // The final, cleaned list of links.
    CLEAN_LINKS: CLEAN_LINKS,
    // Uncomment the line below to see the full original item if you still have issues.
    // FULL_INCOMING_ITEM: $item,
  }
};

return diagnosticOutput;

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

const raw = $input.first().json.data; // Your markdown input

function cleanMarkdown(text) {
  return text
    .replace(/!\[.*?\]\(.*?\)/g, '')
    .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
    .replace(/^\s*(Menu|Send|Skip to content|Call Now Button|Terms & Conditions|Privacy Policy|Site design:.*|Instagram|Envelope|Twitter|Yelp|Facebook)\s*$/gmi, '')
    .replace(/\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}/g, '')
    .replace(/^\s*$/gm, '')
    .replace(/^\s+|\s+$/gm, '')
    .replace(/\n{2,}/g, '\n');
}

const clean = cleanMarkdown(raw);

return [
  {
    json: {
      cleanedPage: clean
    }
  }
];

// Get the single item from the loop's output array.
const item = items[0];

// The 'links' field is a string representing a JSON array.
// JSON.parse() converts that string into a real JavaScript array.
const parsedLinks = JSON.parse(item.json.links);

// Overwrite the old string with the new, correct array.
item.json.links = parsedLinks;

// You also said myNewField is useless. I've killed it for you.
delete item.json.myNewField;

// Return the modified item for the next node in the workflow.
return [item];

